code = """import json

stock_info_results = locals()['var_function-call-7782631597768028952']
union_queries = []
for item in stock_info_results:
    symbol = item['Symbol']
    company_description = item['Company Description']
    
    # Escape single quotes in company_description for SQL string literal
    escaped_company_description = company_description.replace("'", "''")
    
    # Construct the SQL subquery using f-string for better readability and correct quoting.
    # Table names (symbols) are enclosed in double quotes for DuckDB. Python f-string escapes these as \" for the outer string.
    # String literals for company name and date pattern use single quotes.
    subquery = f"SELECT '{escaped_company_description}' AS \"Company Name\", AVG(Volume) AS \"Average Daily Trading Volume 2008\" FROM \"{symbol}\" WHERE Date LIKE '2008%' AND Volume IS NOT NULL;"
    union_queries.append(subquery)

final_query = ' UNION ALL '.join(union_queries)

print('__RESULT__:')
print(json.dumps(final_query))"""

